import React, { lazy, Suspense, useEffect } from 'react'
import { BrowserRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom'
import AdminLayout from './shared/layout/AdminLayout'
import Loading from './shared/components/Loading'
import { authService } from './services/authService'

// Componente para atualizar o título do documento
const PageTitle = () => {
  const location = useLocation()
  
  useEffect(() => {
    const titles: Record<string, string> = {
      '/dashboard': 'Dashboard | Papyros',
      '/assets': 'Ativos | Papyros',
      '/reports': 'Relatórios | Papyros',
      '/settings': 'Configurações | Papyros',
      '/vulns': 'Vulnerabilidades | Papyros',
      '/archived': 'Arquivados | Papyros',
      '/api-explorer': 'API Explorer | Papyros',
      '/login': 'Login | Papyros',
      '/register': 'Registrar | Papyros',
    }
    
    const currentPath = location.pathname
    document.title = titles[currentPath] || 'Papyros'
  }, [location])

  return null
}

// Wrapper de Rota Protegida
const ProtectedRoute = ({ children }: { children: React.ReactNode }) => {
  if (!authService.isAuthenticated()) {
    return <Navigate to="/login" replace />
  }
  return <>{children}</>
}

// Componente de Logout
const Logout = () => {
  useEffect(() => {
    authService.logout()
    // Pequeno delay para garantir que o redirecionamento do logout não interfira
    window.location.href = '/login'
  }, [])
  return <Loading />
}

// Carregamento Lazy das Páginas
const Login = lazy(() => import('./pages/Login'))
const Register = lazy(() => import('./pages/Register'))
const Dashboard = lazy(() => import('./pages/Dashboard'))
const Assets = lazy(() => import('./pages/Assets'))
const AssetDetails = lazy(() => import('./pages/AssetDetails'))
const Reports = lazy(() => import('./pages/Reports'))
const Settings = lazy(() => import('./pages/Settings'))
const Vulns = lazy(() => import('./pages/Vulns'))
const Archived = lazy(() => import('./pages/Archived'))
const ApiExplorer = lazy(() => import('./pages/ApiExplorer'))
const NotFound = lazy(() => import('./pages/NotFound'))
const ErrorBoundary = lazy(() => import('./pages/ErrorBoundary'))

export default function App() {
  return (
    <BrowserRouter>
      <PageTitle />
      <Suspense fallback={<div style={{ height: '100vh' }}><Loading /></div>}>
        <Routes>
          {/* Rota Raiz Condicional */}
          <Route 
            path="/" 
            element={
              authService.isAuthenticated() 
                ? <Navigate to="/dashboard" replace /> 
                : <Navigate to="/login" replace />
            } 
          />

          {/* Rotas Públicas */}
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />

          {/* Rotas Protegidas */}
          <Route 
            path="/" 
            element={
              <ProtectedRoute>
                <AdminLayout />
              </ProtectedRoute>
            }
          >
            <Route path="dashboard" element={<Dashboard />} />
            <Route path="assets" element={<Assets />} />
            <Route path="assets/:id" element={<AssetDetails />} />
            <Route path="reports" element={<Reports />} />
            <Route path="settings" element={<Settings />} />
            <Route path="vulns" element={<Vulns />} />
            <Route path="archived" element={<Archived />} />
            <Route path="api-explorer" element={<ApiExplorer />} />
            <Route path="logout" element={<Logout />} />
          </Route>

          {/* Fallback e Erros */}
          <Route path="/error" element={<ErrorBoundary />} />
          <Route path="*" element={<NotFound />} />
        </Routes>
      </Suspense>
    </BrowserRouter>
  )
}
