import api from './api'

interface LoginResponse {
  token: string
}

export const authService = {
  async login(username: string, password: string): Promise<string> {
    try {
      // Ajuste para garantir que o endpoint corresponda ao esperado pelo backend
      // Se o backend utiliza /auth/login sem o prefixo /api definido no baseURL,
      // podemos usar a URL completa ou ajustar conforme necessário.
      // Mantendo o path relativo, mas preparado para tratamento de erro robusto.
      const response = await api.post<LoginResponse>('/auth/login', {
        username: username,
        password: password,
      })

      const token = response.data?.token
      if (!token) {
        throw new Error('Falha na autenticação: Token não retornado.')
      }

      // Armazenamento seguro no localStorage
      localStorage.setItem('@aBitat:token', token)
      
      // Configuração imediata do header Authorization para chamadas seguintes
      api.defaults.headers.Authorization = `Bearer ${token}`
      
      return token
    } catch (error: any) {
      console.error('Login error details:', error)

      // Captura de falhas de rede (XHR failed / Network Error)
      if (error.code === 'ERR_NETWORK' || !error.response) {
        throw new Error('Erro de conexão: Não foi possível alcançar o servidor. Verifique sua internet.')
      }

      // Tratamento de erros de credenciais ou outros erros da API
      if (error.response?.status === 401) {
        throw new Error('Credenciais inválidas. Verifique seu usuário e senha.')
      }

      const apiMessage = error.response?.data?.message || error.response?.data?.error
      throw new Error(apiMessage || 'Erro interno ao tentar realizar o login.')
    }
  },

  logout() {
    localStorage.removeItem('@aBitat:token')
    delete api.defaults.headers.Authorization
    // Redirecionamento garantido para a página de login
    window.location.href = '/login'
  },

  isAuthenticated(): boolean {
    const token = localStorage.getItem('@aBitat:token')
    return !!token
  },
}
